package cmd

import (
	"context"
	"fmt"
	"os"
	"strings"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/agent"
	gitpkg "github.com/DocumentDrivenDX/ddx/internal/git"
	"github.com/spf13/cobra"
)

func (f *CommandFactory) newBeadReviewCommand() *cobra.Command {
	cmd := &cobra.Command{
		Use:   "review <id>",
		Short: "Generate a review prompt for a bead's implementation",
		Long: `Generate a review-ready prompt for a bead implementation.

The prompt includes:
  - Bead title, description, and acceptance criteria
  - Full content of governing documents (spec-id refs from the bead)
  - Git diff of the reviewed commit (git show)
  - Review instructions with the expected APPROVE/REQUEST_CHANGES/BLOCK output contract

Use --prose to add an advisory prose-quality section derived from the bead
text, using the same deterministic prose checker as ` + "`ddx doc prose`" + `.

By default the commit is taken from the bead's closing_commit_sha field.
Use --from-rev to override.

Pipe the output into ddx agent run:

  ddx bead review <id> | ddx agent run --prompt @-
  ddx bead review <id> --output /tmp/review.md && ddx agent run --prompt /tmp/review.md`,
		Args: cobra.ExactArgs(1),
		RunE: f.runBeadReview,
	}
	cmd.Flags().String("from-rev", "", "Commit SHA to review (default: closing_commit_sha from bead)")
	cmd.Flags().Int("iter", 1, "Review iteration number (shown in prompt header and grade table)")
	cmd.Flags().String("output", "", "Write prompt to file instead of stdout")
	cmd.Flags().Bool("prose", false, "Include advisory prose findings derived from the bead text")
	return cmd
}

func (f *CommandFactory) runBeadReview(cmd *cobra.Command, args []string) error {
	beadID := args[0]
	fromRev, _ := cmd.Flags().GetString("from-rev")
	iter, _ := cmd.Flags().GetInt("iter")
	outputFile, _ := cmd.Flags().GetString("output")
	includeProse, _ := cmd.Flags().GetBool("prose")

	s := f.beadStore()
	b, err := s.Get(beadID)
	if err != nil {
		return err
	}

	// Resolve the commit SHA to review.
	// Priority: --from-rev flag > closing_commit_sha on the bead.
	rev := strings.TrimSpace(fromRev)
	if rev == "" {
		if sha, ok := b.Extra["closing_commit_sha"].(string); ok {
			rev = strings.TrimSpace(sha)
		}
	}
	if rev == "" {
		return fmt.Errorf("no commit to review: use --from-rev <sha>, or close the bead with a commit SHA first (ddx bead close --commit <sha>)")
	}

	// Project root is used for git operations and governing doc file reads.
	projectRoot := gitpkg.FindProjectRoot(f.WorkingDir)
	if projectRoot == "" {
		projectRoot = f.WorkingDir
	}

	// Fetch the git diff for the commit.
	diff, err := beadReviewGitShow(projectRoot, rev)
	if err != nil {
		return fmt.Errorf("git show %s: %w", rev, err)
	}

	// Resolve governing document references from the bead's spec-id field.
	refs := agent.ResolveGoverningRefs(projectRoot, b)

	// Delegate prompt assembly to the single source of truth in the agent
	// package so the CLI handler and the post-merge reviewer cannot drift.
	var prompt string
	if includeProse {
		prompt = agent.BuildReviewPromptWithProse(b, iter, rev, diff, projectRoot, refs)
	} else {
		prompt = agent.BuildReviewPrompt(b, iter, rev, diff, projectRoot, refs)
	}

	if outputFile != "" {
		return os.WriteFile(outputFile, []byte(prompt), 0o644)
	}
	_, err = fmt.Fprint(cmd.OutOrStdout(), prompt)
	return err
}

// beadReviewGitShow runs `git show <rev>` with pathspec exclusions for
// execution-evidence noise so the review prompt's <diff> section stays
// bounded. See agent.EvidenceReviewExcludePathspecs and ddx-39e27896.
func beadReviewGitShow(projectRoot, rev string) (string, error) {
	ctx, cancel := context.WithTimeout(context.Background(), 30*time.Second)
	defer cancel()
	args := append([]string{"show", rev, "--", "."}, agent.EvidenceReviewExcludePathspecs()...)
	out, err := gitpkg.Command(ctx, projectRoot, args...).Output()
	if err != nil {
		return "", err
	}
	return string(out), nil
}

package docprose

import (
	"fmt"
	"regexp"
	"strings"
	"unicode"
)

type Mode string

const (
	ModeTechnical Mode = "technical"
	ModePlanning  Mode = "planning"
	ModePublic    Mode = "public"
)

type Checker struct {
	mode       Mode
	rules      []ruleSpec
	vocabulary Vocabulary
}

func NewChecker(mode Mode, vocabulary Vocabulary) (*Checker, error) {
	if mode == "" {
		mode = ModeTechnical
	}
	rules, err := loadRulePack(string(mode))
	if err != nil {
		return nil, err
	}
	defaultVocab, err := loadDefaultVocabulary()
	if err != nil {
		return nil, err
	}
	if len(vocabulary.Accept) == 0 {
		vocabulary.Accept = defaultVocab.Accept
	}
	if len(vocabulary.Reject) == 0 {
		vocabulary.Reject = defaultVocab.Reject
	}
	return &Checker{
		mode:       mode,
		rules:      rules,
		vocabulary: vocabulary,
	}, nil
}

func (c *Checker) Findings(file, text string) []Finding {
	var findings []Finding
	lines := strings.Split(text, "\n")

	for idx, raw := range lines {
		lineNo := idx + 1
		line := strings.TrimSpace(raw)
		if line == "" {
			continue
		}

		for _, rule := range c.rules {
			if rule.Kind == "repeated_opening" {
				if repeatedOpeningKey(line) != "" {
					findings = append(findings, Finding{
						File:          file,
						Line:          lineNo,
						RuleID:        rule.ID,
						Severity:      rule.Severity,
						Rationale:     rule.Rationale,
						SuggestedEdit: rule.SuggestedEdit,
					})
				}
				continue
			}
			if matchesRule(line, rule) {
				findings = append(findings, Finding{
					File:          file,
					Line:          lineNo,
					RuleID:        rule.ID,
					Severity:      rule.Severity,
					Rationale:     rule.Rationale,
					SuggestedEdit: rule.SuggestedEdit,
				})
			}
		}

		findings = append(findings, c.vocabularyFindings(file, lineNo, line)...)
	}

	return findings
}

func (c *Checker) vocabularyFindings(file string, lineNo int, line string) []Finding {
	var findings []Finding
	lower := strings.ToLower(line)
	for _, reject := range c.vocabulary.Reject {
		if reject == "" {
			continue
		}
		if !containsWord(lower, reject) {
			continue
		}
		if c.termAccepted(reject) {
			continue
		}
		findings = append(findings, Finding{
			File:          file,
			Line:          lineNo,
			RuleID:        "prose.vocabulary.reject",
			Severity:      "warning",
			Rationale:     fmt.Sprintf("The vocabulary term %q is discouraged in default prose because it is too generic.", reject),
			SuggestedEdit: fmt.Sprintf("Replace %q with the project-specific term or concrete noun that names the actual concept.", reject),
		})
	}
	return findings
}

func (c *Checker) termAccepted(term string) bool {
	for _, accept := range c.vocabulary.Accept {
		if accept == "" {
			continue
		}
		if strings.EqualFold(strings.TrimSpace(accept), strings.TrimSpace(term)) {
			return true
		}
	}
	return false
}

func matchesRule(line string, rule ruleSpec) bool {
	if len(rule.ContainsAny) == 0 {
		return false
	}
	lower := strings.ToLower(line)
	for _, phrase := range rule.ContainsAny {
		if phrase == "" {
			continue
		}
		if strings.Contains(lower, strings.ToLower(phrase)) {
			return true
		}
	}
	return false
}

func repeatedOpeningKey(line string) string {
	first, rest, ok := cutSentence(line)
	if !ok {
		return ""
	}
	second, _, ok := cutSentence(rest)
	if !ok {
		return ""
	}
	first = normalizeSentence(first)
	second = normalizeSentence(second)
	if first == "" || first != second {
		return ""
	}
	return first
}

func cutSentence(s string) (head, tail string, ok bool) {
	s = strings.TrimSpace(s)
	if s == "" {
		return "", "", false
	}
	for i, r := range s {
		if r == '.' || r == '!' || r == '?' {
			return strings.TrimSpace(s[:i+1]), strings.TrimSpace(s[i+1:]), true
		}
	}
	return "", "", false
}

func normalizeSentence(s string) string {
	s = strings.ToLower(strings.TrimSpace(s))
	s = strings.TrimFunc(s, func(r rune) bool {
		return unicode.IsPunct(r) || unicode.IsSpace(r)
	})
	s = strings.Join(strings.Fields(s), " ")
	return s
}

func containsWord(haystack, needle string) bool {
	needle = strings.TrimSpace(needle)
	if needle == "" {
		return false
	}
	pattern := `(?i)(^|[^[:alnum:]_])` + regexp.QuoteMeta(needle) + `([^[:alnum:]_]|$)`
	return regexp.MustCompile(pattern).FindStringIndex(haystack) != nil
}

