		t.Fatalf("execute: %v\noutput: %s", err, stdout.String())
	}

	out := stdout.String()
	if !strings.HasPrefix(out, "<bead-review>\n") {
		t.Errorf("output missing <bead-review> opener; got prefix %q", firstLine(out))
	}
