		t.Errorf("output missing wired bead header; got:\n%s", out)
	}
	if !strings.Contains(out, `<diff rev=`+quote(sha)+`>`) {
		t.Errorf("output missing diff section for rev %s; got:\n%s", sha, out)
	}
